const lead = $('Procesar de a 1').item.json;
const responseText = $json.content?.[0]?.text || '{}';

let mensajes;
try {
  const match = responseText.match(/\{[\s\S]*\}/);
  mensajes = match ? JSON.parse(match[0]) : {};
} catch(e) {
  mensajes = {};
}

return [{
  json: {
    // Identificador para actualizar la fila correcta
    row_number:          lead.row_number,
    place_id:            lead.place_id,
    // Mensajes generados
    email_msg1_asunto:   mensajes.email_msg1_asunto || '',
    email_msg1_cuerpo:   mensajes.email_msg1_cuerpo || '',
    email_msg2_asunto:   mensajes.email_msg2_asunto || '',
    email_msg2_cuerpo:   mensajes.email_msg2_cuerpo || '',
    email_msg3_asunto:   mensajes.email_msg3_asunto || '',
    email_msg3_cuerpo:   mensajes.email_msg3_cuerpo || '',
    whatsapp_msg1:       mensajes.whatsapp_msg1 || '',
    whatsapp_msg2:       mensajes.whatsapp_msg2 || '',
    whatsapp_msg3:       mensajes.whatsapp_msg3 || '',
    status:              'listo_para_enviar',
    googleSheetsId:      $('Configuración').item.json.googleSheetsId
  }
}];
